/* ============================================
   RTL – Right-to-Left Support for Arabic
   ============================================ */

/* Base RTL text alignment */
[dir="rtl"] {
  text-align: right;
}

/* LTR overrides inside RTL (e.g. phone numbers, emails) */
[dir="rtl"] [dir="ltr"] {
  text-align: left;
  unicode-bidi: embed;
}

/* Flip directional icons in RTL */
[dir="rtl"] .rtl-flip {
  transform: scaleX(-1);
}

/* Reverse sibling spacing for RTL (margin-left → margin-right) */
[dir="rtl"] .rtl-space-reverse > * + * {
  margin-right: calc(var(--space-reverse, 0.25rem) * -1);
  margin-left: 0;
}

/* Scrollbar direction */
[dir="rtl"] ::-webkit-scrollbar {
  direction: rtl;
}

/* Input number spinners */
[dir="rtl"] input[type="number"] {
  direction: ltr;
  text-align: right;
}

/* Force LTR for email/url inputs */
[dir="rtl"] input[type="email"],
[dir="rtl"] input[type="url"] {
  direction: ltr;
  text-align: right;
}

import { PrismaClient, UserRole, ProjectStatus } from "@prisma/client";
import { PrismaPg } from "@prisma/adapter-pg";
import bcrypt from "bcryptjs";

/* ============================================
   Prisma Seed Script
   Creates: Owner user → Demo client → Demo project
   ============================================ */

const adapter = new PrismaPg({
  connectionString: process.env.DATABASE_URL,
});

const prisma = new PrismaClient({ adapter });

async function main() {
  console.log("🌱 Seeding database...\n");

  const hashedPassword = await bcrypt.hash("Owner@123", 12);

  // 1. Create owner user
  const owner = await prisma.user.upsert({
    where: { email: "owner@pixelpixel.hub" },
    update: {
      password: hashedPassword,
      role: UserRole.OWNER,
    },
    create: {
      email: "owner@pixelpixel.hub",
      name: "Owner",
      password: hashedPassword,
      role: UserRole.OWNER,
    },
  });
  console.log(`  ✓ Owner user: ${owner.email} (${owner.id})`);

  // 2. Create demo client
  const client = await prisma.client.upsert({
    where: { token: "demo-client-token-00000000" },
    update: {},
    create: {
      userId: owner.id,
      clientCode: "CL-000001",
      name: "Demo Client",
      email: "demo@example.com",
      phone: "0500000000",
      token: "demo-client-token-00000000",
      status: "ACTIVE",
    },
  });
  console.log(`  ✓ Demo client: ${client.email} (${client.id})`);

  // 3. Create demo project
  const project = await prisma.project.upsert({
    where: { token: "demo-project-token-00000000" },
    update: {},
    create: {
      clientId: client.id,
      projectCode: "PR-000001",
      name: "Demo Project",
      description: "مشروع تجريبي للعرض",
      status: ProjectStatus.DRAFT,
      retentionPeriod: "TWENTY_FOUR_HOURS",
      deadline: new Date("2026-12-31"),
      token: "demo-project-token-00000000",
    },
  });
  console.log(`  ✓ Demo project: ${project.name} (${project.id})`);

  console.log("\n✅ Seed completed successfully!");
  console.log(`\n📋 Login credentials:`);
  console.log(`   Email:    owner@pixelpixel.hub`);
  console.log(`   Password: Owner@123`);
}

main()
  .catch((error) => {
    console.error("❌ Seed failed:", error);
    process.exit(1);
  })
  .finally(async () => {
    await prisma.$disconnect();
  });

import { z } from "zod";

/* ============================================
   Environment Variable Validation
   Fail immediately if any required variable
   is missing on the server.
   ============================================ */

const envSchema = z.object({
  /* ── Database ───────────────────────────── */
  DATABASE_URL: z.string().min(1, "DATABASE_URL is required"),
  DIRECT_URL: z.string().min(1, "DIRECT_URL is required"),

  /* ── Supabase ───────────────────────────── */
  NEXT_PUBLIC_SUPABASE_URL: z
    .string()
    .url("NEXT_PUBLIC_SUPABASE_URL must be a valid URL")
    .min(1, "NEXT_PUBLIC_SUPABASE_URL is required"),
  NEXT_PUBLIC_SUPABASE_ANON_KEY: z
    .string()
    .min(1, "NEXT_PUBLIC_SUPABASE_ANON_KEY is required"),
  SUPABASE_SERVICE_ROLE_KEY: z
    .string()
    .min(1, "SUPABASE_SERVICE_ROLE_KEY is required"),

  /* ── Cloudflare R2 ──────────────────────── */
  R2_ENDPOINT: z
    .string()
    .url("R2_ENDPOINT must be a valid URL")
    .min(1, "R2_ENDPOINT is required"),
  R2_ACCESS_KEY: z.string().min(1, "R2_ACCESS_KEY is required"),
  R2_SECRET_KEY: z.string().min(1, "R2_SECRET_KEY is required"),
  R2_BUCKET: z.string().min(1, "R2_BUCKET is required"),
  R2_PUBLIC_URL: z
    .string()
    .url("R2_PUBLIC_URL must be a valid URL")
    .min(1, "R2_PUBLIC_URL is required"),

  /* ── App (public) ───────────────────────── */
  NEXT_PUBLIC_APP_NAME: z.string().default("Photography Pixel Hub"),
  NEXT_PUBLIC_APP_URL: z
    .string()
    .url("NEXT_PUBLIC_APP_URL must be a valid URL")
    .default("http://localhost:3000"),

  /* ── Auth ──────────────────────────────── */
  AUTH_SECRET: z.string().min(1, "AUTH_SECRET is required"),

  /* ── Node Env ──────────────────────────── */
  NODE_ENV: z
    .enum(["development", "production", "test"])
    .default("development"),
});

export type Env = z.infer<typeof envSchema>;

/**
 * Parse and validate environment variables.
 * Throws immediately if any required variable is missing or invalid.
 *
 * This function is server-only — never import from client components.
 */
function loadEnv(): Env {
  const parsed = envSchema.safeParse(process.env);

  if (!parsed.success) {
    const errors = parsed.error.issues
      .map((issue) => `  ✗ ${issue.path.join(".")}: ${issue.message}`)
      .join("\n");

    throw new Error(
      `\n❌ Invalid environment variables:\n${errors}\n\n` +
        `Please check your .env file and ensure all required variables are set.\n`
    );
  }

  return parsed.data;
}

export const env = loadEnv();

import { NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";
import { storageService } from "@/lib/storage/storage.service";

/* ============================================
   Health Check API Route
   /api/health
   Verifies: Database, Storage, Auth config.
   ============================================ */

export async function GET() {
  const checks = {
    database: false,
    storage: false,
    auth: false,
    timestamp: new Date().toISOString(),
  };

  const errors: string[] = [];

  // 1. Database check
  try {
    await prisma.$queryRaw`SELECT 1`;
    checks.database = true;
  } catch (err) {
    errors.push(`Database: ${err instanceof Error ? err.message : "connection failed"}`);
  }

  // 2. Storage check (just verify config exists, don't make network call)
  try {
    if (storageService.bucket) {
      checks.storage = true;
    } else {
      errors.push("Storage: no bucket configured");
    }
  } catch (err) {
    errors.push(`Storage: ${err instanceof Error ? err.message : "config error"}`);
  }

  // 3. Auth check (verify AUTH_SECRET is set)
  try {
    const secret = process.env.AUTH_SECRET;
    if (secret && secret.length > 0) {
      checks.auth = true;
    } else {
      errors.push("Auth: AUTH_SECRET not set");
    }
  } catch {
    errors.push("Auth: configuration error");
  }

  const isHealthy = checks.database && checks.storage && checks.auth;

  return NextResponse.json(
    {
      status: isHealthy ? "healthy" : "unhealthy",
      checks,
      errors: errors.length > 0 ? errors : undefined,
    },
    { status: isHealthy ? 200 : 503 }
  );
}

/* ============================================
   Job Scheduler
   Registers all recurring jobs with their intervals.
   ============================================ */

import { cleanupExpiredProjects } from "../cleanup/expired-projects";
import { sendPendingEmailNotifications } from "../emails/send-notifications";

export type ScheduledJob = {
  name: string;
  intervalMs: number;
  handler: () => Promise<void>;
};

export const scheduledJobs: ScheduledJob[] = [
  {
    name: "cleanup-expired-projects",
    intervalMs: 60 * 60 * 1000, // 1 hour
    handler: cleanupExpiredProjects,
  },
  {
    name: "send-pending-emails",
    intervalMs: 5 * 60 * 1000, // 5 minutes
    handler: sendPendingEmailNotifications,
  },
];

/**
 * Start the job scheduler.
 * Call this once during application bootstrap (e.g., in instrumentation.ts).
 */
export function startScheduler(): void {
  for (const job of scheduledJobs) {
    setInterval(() => {
      job.handler().catch((error) => {
        console.error(`[job:${job.name}] failed:`, error);
      });
    }, job.intervalMs);

    if (process.env.NODE_ENV !== "production") {
      console.log(`[scheduler] registered: ${job.name}`);
    }
  }
}

