import { createClient } from "@supabase/supabase-js";

/**
 * Supabase admin client using the service role key.
 *
 * Bypasses Row Level Security — use ONLY on the server for
 * privileged operations (webhooks, system jobs, seeds).
 * NEVER expose this client to the browser.
 */
export function createSupabaseAdminClient() {
  return createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!,
    {
      auth: {
        autoRefreshToken: false,
        persistSession: false,
      },
    }
  );
}

import { createBrowserClient } from "@supabase/ssr";

/**
 * Supabase browser client.
 *
 * Uses the anon key — safe for client-side usage.
 * Respects the user's session via cookies managed by @supabase/ssr.
 */
export function createSupabaseBrowserClient() {
  return createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  );
}

import { createServerClient } from "@supabase/ssr";
import { cookies } from "next/headers";

/**
 * Supabase server client for Server Components, Server Actions, and Route Handlers.
 *
 * Uses the anon key with cookie-based session management.
 */
export async function createSupabaseServerClient() {
  const cookieStore = await cookies();

  return createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll();
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options)
            );
          } catch {
            // Called from a Server Component — safe to ignore
            // if session refresh is handled by middleware.
          }
        },
      },
    }
  );
}

